source .venv/bin/activate && python -c "
import json,glob
want={
 'Future Lens':1,'Internal Planning in Language Models':1,\"What's the plan\":1,
 'Recursive Introspection':1,'Mitigating Lost in Multi-turn':1,'Not All Thoughts are Generated Equal':1,
 'TRUTH DECAY':1,'Measuring Sycophancy of Language Models in Multi-turn':1,'Overconfidence in Initial Choices':1,
 'CoT-UQ':1,'Uncertainty Profiles for LLMs':1,
}
seen={}
for fn in glob.glob('paper_search_results/search*.json'):
    d=json.load(open(fn))
    for p in d['papers']:
        t=p['title']
        for w in want:
            if w.lower() in t.lower() and t not in seen:
                seen[t]=p['abstract'][:700]
for t,a in seen.items():
    print('###',t)
    print(a,'\n')
"
